--------------------------------------------------------------------------------
-- Weight ROM Module
-- Dual-port ROM for storing CNN weights
-- Initialized from .mif files generated by extract_weights.py
--
-- This is a wrapper - actual ROM will be Quartus ALTSYNCRAM megafunction
-- For now, use simple array-based ROM
--
-- Author: Marly Capstone
-- Date: March 2026
--------------------------------------------------------------------------------

library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;

entity weight_rom is
    generic (
        DATA_WIDTH : integer := 16;
        ADDR_WIDTH : integer := 14;  -- 2^14 = 16K locations
        INIT_FILE  : string := "weights.mif"
    );
    port (
        clk     : in  std_logic;

        -- Port A (fixed size for all ROM instances)
        addr_a  : in  integer range 0 to 16383;  -- Max 14-bit address
        data_a  : out signed(DATA_WIDTH-1 downto 0);

        -- Port B (optional second port for parallel access)
        addr_b  : in  integer range 0 to 16383;  -- Max 14-bit address
        data_b  : out signed(DATA_WIDTH-1 downto 0)
    );
end weight_rom;

architecture Behavioral of weight_rom is

    -- ROM storage type
    type rom_type is array (0 to 2**ADDR_WIDTH-1) of signed(DATA_WIDTH-1 downto 0);

    -- Initialize ROM (will be replaced with .mif file in Quartus synthesis)
    signal rom_data : rom_type := (others => (others => '0'));

    -- Quartus attributes for proper ROM inference
    attribute ram_init_file : string;
    attribute ram_init_file of rom_data : signal is INIT_FILE;

    attribute ramstyle : string;
    attribute ramstyle of rom_data : signal is "M4K";  -- Force block RAM usage

begin

    -- Dual-port read process (with bounds checking)
    process(clk)
    begin
        if rising_edge(clk) then
            if addr_a < 2**ADDR_WIDTH then
                data_a <= rom_data(addr_a);
            else
                data_a <= (others => '0');
            end if;

            if addr_b < 2**ADDR_WIDTH then
                data_b <= rom_data(addr_b);
            else
                data_b <= (others => '0');
            end if;
        end if;
    end process;

end Behavioral;
